it = iter(sys.stdin.read().split())
n = int(next(it))
nums = [int(next(it)) for _ in range(n)]
def gcd(a, b):
   while b:
       a, b = b, a % b
   return a
result = nums[0]
for num in nums[1:]:
   result = gcd(result, num)
for i in range(2, result + 1):
   if result % i == 0:
       print(i)
       break
else:
   print(-1)

